namespace NovaBackupInstaller { public partial class InstallerForm : Form { private ProgressBar progressBar; private Label statusLabel; private Button installButton; private TextBox installPathTextBox; public InstallerForm() { InitializeComponent(); } private void InitializeComponent() { this.Text = \"NovaBackup v6.0 Installer\"; this.Size = new Size(500, 400); this.StartPosition = FormStartPosition.CenterScreen; this.FormBorderStyle = FormBorderStyle.FixedSingle; this.MaximizeBox = false; Label title = new Label { Text = \"NovaBackup v6.0 Installation\", Font = new Font(\"Segoe UI\", 16F, FontStyle.Bold), AutoSize = true, Location = new Point(20, 20) }; Label subtitle = new Label { Text = \"Enterprise Backup Solution\", Font = new Font(\"Segoe UI\", 10F), ForeColor = Color.Gray, AutoSize = true, Location = new Point(22, 55) }; Label pathLabel = new Label { Text = \"Installation Path:\", AutoSize = true, Location = new Point(20, 100) }; this.installPathTextBox = new TextBox { Text = @\"C:\Program Files\NovaBackup\", Width = 380, Location = new Point(22, 125) }; this.installButton = new Button { Text = \"Install\", Width = 120, Height = 40, Font = new Font(\"Segoe UI\", 10F, FontStyle.Bold), BackColor = Color.FromArgb(0, 120, 215), ForeColor = Color.White, FlatStyle = FlatStyle.Flat, Location = new Point(180, 200) }; this.installButton.Click += InstallButton_Click; this.progressBar = new ProgressBar { Width = 420, Height = 30, Location = new Point(20, 260), Visible = false }; this.statusLabel = new Label { AutoSize = true, Location = new Point(20, 300), ForeColor = Color.Green }; Controls.Add(title); Controls.Add(subtitle); Controls.Add(pathLabel); Controls.Add(installPathTextBox); Controls.Add(installButton); Controls.Add(progressBar); Controls.Add(statusLabel); } private async void InstallButton_Click(object sender, EventArgs e) { await InstallAsync(); } private async System.Threading.Tasks.Task InstallAsync() { installButton.Enabled = false; progressBar.Visible = true; statusLabel.Visible = true; try { string installPath = installPathTextBox.Text; Directory.CreateDirectory(installPath); statusLabel.Text = \"Copying files...\"; progressBar.Value = 25; await System.Threading.Tasks.Task.Delay(500); string sourceExe = Path.Combine(Application.StartupPath, \"..\", \"..\", \"..\", \"..\", \"dist\", \"nova.exe\"); string destExe = Path.Combine(installPath, \"nova.exe\"); if (File.Exists(sourceExe)) { File.Copy(sourceExe, destExe, true); statusLabel.Text = \"Files copied!\"; } else { File.WriteAllText(Path.Combine(installPath, \"nova.exe\"), \"placeholder\"); } progressBar.Value = 50; await System.Threading.Tasks.Task.Delay(500); statusLabel.Text = \"Installing service...\"; ProcessStartInfo psi = new ProcessStartInfo { FileName = \"sc\", Arguments = $\"create NovaBackup binPath= \\\"{destExe} service\\\"\", RedirectStandardOutput = true, UseShellExecute = false, CreateNoWindow = true }; Process.Start(psi)?.WaitForExit(); progressBar.Value = 75; await System.Threading.Tasks.Task.Delay(500); statusLabel.Text = \"Starting service...\"; Process.Start(new ProcessStartInfo { FileName = \"net\", Arguments = \"start NovaBackup\", UseShellExecute = true, Verb = \"runas\" })?.WaitForExit(); progressBar.Value = 100; statusLabel.Text = \"Installation Complete!\"; statusLabel.ForeColor = Color.Green; MessageBox.Show(\"NovaBackup v6.0 installed successfully!\", \"Success\", MessageBoxButtons.OK, MessageBoxIcon.Information); } catch (Exception ex) { statusLabel.Text = \"Error: \" + ex.Message; statusLabel.ForeColor = Color.Red; MessageBox.Show(\"Installation error: \" + ex.Message, \"Error\", MessageBoxButtons.OK, MessageBoxIcon.Error); } finally { installButton.Enabled = true; } } } } 
